function SceneRunner() {
  const [active, setActive] = React.useState(null);
  const [running, setRunning] = React.useState(null);

  const scenes = [
    { id: 'morning', name: 'Morning', icon: '☀️', color: '#f59e0b' },
    { id: 'evening', name: 'Evening', icon: '🌙', color: '#8b5cf6' },
    { id: 'movie', name: 'Movie', icon: '🎬', color: '#ef4444' },
    { id: 'sleep', name: 'Sleep', icon: '💤', color: '#3b82f6' },
    { id: 'away', name: 'Away', icon: '🚪', color: '#10b981' }
  ];

  const runScene = (id) => {
    setRunning(id);
    setTimeout(() => { setActive(id); setRunning(null); }, 1500);
  };

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', padding: 16, borderRadius: 8, boxSizing: 'border-box', display: 'flex', flexDirection: 'column', gap: 10 }}>
      <div style={{ fontSize: 14, fontWeight: 600, color: '#9ca3af' }}>Scenes</div>
      {scenes.map(s => (
        <button key={s.id} onClick={() => runScene(s.id)} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 14px', borderRadius: 8, border: 'none', background: active === s.id ? s.color + '22' : '#1f2937', boxShadow: active === s.id ? 'inset 0 0 0 2px ' + s.color : 'none', cursor: 'pointer', transition: 'all 0.2s' }}>
          <span style={{ fontSize: 20 }}>{s.icon}</span>
          <span style={{ flex: 1, textAlign: 'left', color: '#f3f4f6', fontWeight: 600, fontSize: 14 }}>{s.name}</span>
          {running === s.id ? (
            <span style={{ fontSize: 12, color: s.color }}>Running...</span>
          ) : active === s.id ? (
            <span style={{ fontSize: 12, color: s.color, fontWeight: 600 }}>Active</span>
          ) : null}
        </button>
      ))}
    </div>
  );
}
render(<SceneRunner/>);
